```plantuml
@startuml

package "java" {
    package "time" {
        class LocalDate
    }
    package "util" {
        interface List <<I>>
        class URL
    }
}

package "org" {
    package "springframework" {
        package "hateoas" {
            class RepresentationModel
        }
    }
}

package "com" {
    package "acme" {
        package "filiale" {
            package "rest" {
                class KundeModel <<entity>> {
                    name : String
                    email : String
                    kategorie: Int
                    hasNewsletter: Boolean
                    geburtsdatum: LocalDate
                    homepage: URL
                    geschlecht: GeschlechtType
                    familienstand: FamilienstandType
                    interessen: List<InteresseType>
                }
            }
            package "entity" {
                class Kunde
                class Umsatz
                class Adresse
                enum GeschlechtType
                enum FamilienstandType
                enum InteresseType
            }
        }
    }
}

KundeModel --|> RepresentationModel

KundeModel ..> LocalDate
KundeModel ..> URL
KundeModel ..> List

KundeModel *-- "0..1" Umsatz : umsatz
KundeModel *-- "1" Adresse : adresse

KundeModel ..> GeschlechtType
KundeModel ..> FamilienstandType
KundeModel ..> InteresseType

KundeModel ..> Kunde

@enduml
